mapper.select:
${pagingTop} SELECT basket_idx, homepage_id, member_key, title, lib_name, call_no, author, loca, ctrl_no, image_url, add_date, item_type, publer, (select context_path from cms_homepage where homepage_id = A.homepage_id) AS context_path FROM BOOK_BASKET A WHERE member_key = #{member_key}
AND ${search_type} LIKE '%' || #{search_text} || '%'
ORDER BY ${sortField} ${sortType} ${pagingBottom}

mapper.delete:
DELETE FROM
	BOOK_BASKET
WHERE
	homepage_id = #{homepage_id}
AND	basket_idx = #{basket_idx}
AND	member_key = #{member_key}

mapper.select:
SELECT 
	COUNT(*) 
FROM 
	BOOK_BASKET 
WHERE 
	homepage_id = #{homepage_id} 
AND ctrl_no = #{ctrl_no} 
AND member_key = #{member_key}
